import React, { useState, useEffect } from 'react';

function CustomParallax({ scrollPercentage, largeLayers, mediumLayers, smallLayers }) {
  const [windowSize, setWindowSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight
  });

  useEffect(() => {
    const handleResize = () => {
      setWindowSize({
        width: window.innerWidth,
        height: window.innerHeight
      });
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  const chooseLayersByResolution = () => {
    if (windowSize.width >= 769) {
      return largeLayers;
    } else if (windowSize.width >= 577) {
      return mediumLayers;
    } else {
      return smallLayers;
    }
  };

  const chosenLayers = chooseLayersByResolution();

  return (
    <div className="CustomParallax" style={{ position: 'relative' }}>
      {/* Capas de paralaje */}
      {chosenLayers.map((layer, index) => (
        <div
          key={index}
          className={`Layer${index + 1}`}
          style={{
            backgroundImage: `url('${layer.image}')`,
            backgroundPositionX: `calc(${scrollPercentage * layer.speed}% + ${layer.offset})`
          }}
        ></div>
      ))}

      {/* Texto "Scroll" */}
      <div
        className="ScrollText"
        style={{
          position: 'absolute',
          top: `${scrollPercentage * 50}%`, // Desplazamiento vertical basado en el scrollPercentage
          left: '50%',
          transform: 'translate(-50%, -50%)',
          fontSize: '24px',
          fontWeight: 'bold',
          color: 'white',
          transition: 'top 0.1s ease-out' // Transición suave
        }}
      >
        Scroll
      </div>
    </div>
  );
}

export default CustomParallax;
